import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import GroupCard from '../components/GroupCard';
import '../styles/MyGroup.css'; 

// 🔄 Utilisateur fictif pour tests sans back
const mockCurrentUser = {
    username: "alice"
};

const MyGroups = ({ currentUser = mockCurrentUser }) => {
    const [groups, setGroups] = useState([]);
    const [isLoading, setIsLoading] = useState(true);

    

    // Données simulées
    const mockGroups = [
        {
            id: 1,
            name: "Groupe A",
            members: ["alice", "bob", "charlie"],
            creator: "alice"
        },
        {
            id: 2,
            name: "Groupe B",
            members: ["alice", "david", "eve"],
            creator: "alice"
        },
        {
            id: 3,
            name: "Groupe C",
            members: ["bob", "david"],
            creator: "bob"
        }
    ];

    useEffect(() => {
        if (!currentUser?.username) return;

        setTimeout(() => {
            const userGroups = mockGroups.filter(group =>
                group.members.includes(currentUser.username)
            );
            setGroups(userGroups);
            setIsLoading(false);
        }, 1000);
    }, [currentUser]);

    return (
        <div className="my-groups-page px-6 py-4">
            <h1 className="text-2xl font-bold mb-4">Mes Groupes</h1>

            {isLoading ? (
                <p className="text-gray-500">Chargement des groupes...</p>
            ) : (
                <>
                    <div className="group-list grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {groups.length > 0 ? (
                            groups.map(group => (
                                <GroupCard
                                    key={group.id}
                                    id={group.id}
                                    name={group.name}
                                    members={group.members}
                                    creator={group.creator}
                                />
                            ))
                        ) : (
                            <p className="text-red-500">Tu n'as rejoint aucun groupe pour l'instant.</p>
                        )}
                    </div>

                    <div className="mt-6">
                        <Link
                            to="/create-group"
                            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded shadow"
                        >
                            Créer un nouveau groupe
                        </Link>
                    </div>
                </>
            )}
        </div>
    );
};

export default MyGroups;
